import json

good = '{"email": "maya@promptdojo.dev", "severity": 3}'
no_email = '{"severity": 3}'
bad_severity = '{"email": "maya@promptdojo.dev", "severity": 9}'

def safe_extract(raw):
    try:
        data = json.loads(raw)
    except json.JSONDecodeError:
        return {"ok": False, "error": "bad json"}
    if "email" not in data or not isinstance(data["email"], str) or not data["email"]:
        return {"ok": False, "error": "missing email"}
    sev = data.get("severity")
    if not isinstance(sev, int) or sev < 1 or sev > 5:
        return {"ok": False, "error": "bad severity"}
    return {"ok": True, "data": data}

for raw in [good, no_email, bad_severity]:
    result = safe_extract(raw)
    if result["ok"]:
        print(f"ok=True email={result['data']['email']}")
    else:
        print(f"ok=False error={result['error']}")

guarded_app = {
    "name": "GuardedApp",
    "validates_model_output": True,
    "validates_user_input": True,
    "validates_external_api_returns": True,
    "validates_db_reads": True,
}

yolo_service = {
    "name": "YOLOService",
    "validates_model_output": True,
    "validates_user_input": False,
    "validates_external_api_returns": False,
    "validates_db_reads": False,
}

def audit_boundaries(system):
    boundaries = [
        "validates_model_output",
        "validates_user_input",
        "validates_external_api_returns",
        "validates_db_reads",
    ]
    score = sum(25 for b in boundaries if system.get(b))
    if score >= 75:
        verdict = "hardened"
    elif score >= 50:
        verdict = "mostly-safe"
    elif score >= 25:
        verdict = "leaky"
    else:
        verdict = "trust-everything"
    return {"score": score, "verdict": verdict}

print(f"GuardedApp:  {audit_boundaries(guarded_app)}")
print(f"YOLOService: {audit_boundaries(yolo_service)}")

systems = [
    {"name": "BillingApp",     "validates_model_output": True,  "validates_user_input": True,  "validates_external_api_returns": True,  "validates_db_reads": True},
    {"name": "MailerBot",      "validates_model_output": True,  "validates_user_input": True,  "validates_external_api_returns": True,  "validates_db_reads": False},
    {"name": "AnalyticsDash",  "validates_model_output": True,  "validates_user_input": True,  "validates_external_api_returns": False, "validates_db_reads": False},
    {"name": "ChatWidget",     "validates_model_output": True,  "validates_user_input": False, "validates_external_api_returns": False, "validates_db_reads": False},
    {"name": "PrototypeX",     "validates_model_output": False, "validates_user_input": False, "validates_external_api_returns": False, "validates_db_reads": False},
]

BOUNDARIES = (
    "validates_model_output",
    "validates_user_input",
    "validates_external_api_returns",
    "validates_db_reads",
)

def score_system(system):
    return sum(25 for b in BOUNDARIES if system.get(b))

def verdict_for(score):
    if score >= 75:
        return "hardened"
    if score >= 50:
        return "mostly-safe"
    if score >= 25:
        return "leaky"
    return "trust-everything"

def triage_systems(systems):
    verdicts = {s["name"]: verdict_for(score_system(s)) for s in systems}
    riskiest = min(systems, key=score_system)["name"]
    return verdicts, riskiest

verdicts, riskiest = triage_systems(systems)
print(f"verdicts: {verdicts}")
print(f"riskiest: {riskiest}")
